questions.reponse:
```javascript
const { Sequelize } = require('sequelize');
const sequelize = new Sequelize('gestion_ecole', 'postgres', 'passer123', {
  host: 'localhost',
  dialect: 'postgres',
  port: 5432,
  logging: false
});
module.exports = sequelize;
```

```javascript
module.exports = (sequelize, DataTypes) => {
  const Filiere = sequelize.define('Filiere', {
    nom: { type: DataTypes.STRING, allowNull: false }
  });
  Filiere.associate = (models) => {
    Filiere.hasMany(models.Etudiant, { foreignKey: 'filiereId' });
  };
  return Filiere;
};
```

```javascript
module.exports = (sequelize, DataTypes) => {
  const Etudiant = sequelize.define('Etudiant', {
    nom: { type: DataTypes.STRING, allowNull: false },
    email: { type: DataTypes.STRING, allowNull: false, unique: true }
  });
  Etudiant.associate = (models) => {
    Etudiant.belongsTo(models.Filiere, { foreignKey: 'filiereId' });
  };
  return Etudiant;
};
```

